solution: ```class Solution {
public:
    int kthFactor(int n, int k) {
        int cnt = 0;
        for (int i = 1; i * i <= n; ++i) {
            if (n % i == 0) {
                ++cnt;
                if (cnt == k) return i;
            }
        }
        int upperStart = static_cast<int>(std::sqrt(n));
        if (upperStart * upperStart == n) --upperStart;
        for (int i = upperStart; i >= 1; --i) {
            if (n % i == 0) {
                ++cnt;
                if (cnt == k) return n / i;
            }
        }
        return -1;
    }
};
